104→        } else {
105→            // 无发布时间 = 立即发布
106→            publishTime = now;
107→        }
108→
109→        // 判断是否定时：发布时间比当前晚 10 分钟以上才算定时
110→        boolean isTimed = publishTime.isAfter(now.plusMinutes(10));
111→        // 明确传了未来时间（超过1分钟容差）但不足10分钟，拒绝；1分钟内视为"立即发布"兼容时钟偏差
112→        if (!isTimed && StringUtils.hasText(ro.getPublishTime()) && publishTime.isAfter(now.plusMinutes(1))) {
113→            throw new BusinessException("定时发布时间必须晚于当前时间至少 10 分钟");
114→        }
115→
116→        // 校验过期时间
117→        if (StringUtils.hasText(ro.getExpireTime())) {
118→            LocalDateTime expireTime = LocalDateTime.parse(ro.getExpireTime(), DATE_TIME_FORMATTER);
119→            if (!expireTime.isAfter(publishTime)) {
120→                throw new BusinessException("过期时间必须晚于发布时间");
121→            }
122→        }
123→
124→        // 2. 获取当前用户信息
125→        Long userId = SessionContext.getUserId();
126→        UserSimpleInfoVo userInfo = apitableGrpcClientService.getUserById(userId);
127→        String userName = userInfo != null ? userInfo.getNickName() : "";
128→
129→        // 3. 如果是编辑（announcementId != null），将旧公告下线
130→        if (ro.getAnnouncementId() != null) {
131→            AnnouncementEntity old = announcementMapper.selectById(ro.getAnnouncementId());
132→            if (old != null) {
133→                old.setStatus(AnnouncementStatus.OFFLINE.getCode());
134→                old.setOfflineTime(now);
135→                announcementMapper.updateById(old);
136→                log.info("[lbl][2210-公告][Announcement][UPDATE] 编辑操作将旧公告下线, announcementId={}", old.getId());
137→            }
138→        }
139→
140→        // 4. 检查同类型（spaceId + category）是否有当前生效公告，自动下线
141→        offlineActiveAnnouncementByCategory(ro.getSpaceId(), ro.getAnnouncementCategory(), now);
142→
143→        // 5. 构建新公告实体（始终 INSERT）
144→        AnnouncementEntity entity = new AnnouncementEntity();
145→        entity.setTitle(ro.getTitle());
146→        entity.setContent(ro.getContent());
147→        entity.setIsPopup(ro.getIsPopup() != null ? ro.getIsPopup() : false);
148→        entity.setSpaceId(ro.getSpaceId());
149→        entity.setAnnouncementCategory(ro.getAnnouncementCategory());
150→        entity.setCreatorId(userId);
151→        entity.setCreatorName(userName);
152→        entity.setPublisherId(userId);
153→        entity.setPublisherName(userName);
154→        entity.setPublishTime(publishTime);
155→        if (StringUtils.hasText(ro.getExpireTime())) {
156→            entity.setExpireTime(LocalDateTime.parse(ro.getExpireTime(), DATE_TIME_FORMATTER));
157→        }
158→
159→        String operationMessage;
160→        if (isTimed) {
161→            // 6. 定时发布
162→            entity.setType(AnnouncementType.TIMED.getCode());
163→            entity.setStatus(AnnouncementStatus.TIMED.getCode());
164→            operationMessage = "公告已设置定时发布";
165→        } else {
166→            // 7. 立即发布
167→            entity.setType(AnnouncementType.IMMEDIATE.getCode());
168→            entity.setStatus(AnnouncementStatus.PUBLISHED.getCode());
169→            entity.setPublishTime(now);
170→            operationMessage = "公告已立即发布";
171→        }
172→
173→        // 8. INSERT 新实体
174→        announcementMapper.insert(entity);
175→        log.info("[lbl][2210-公告][Announcement][CREATE] 新公告已创建, announcementId={}, status={}, category={}, spaceId={}", entity.getId(), entity.getStatus(), entity.getAnnouncementCategory(), entity.getSpaceId());
176→
177→        // 9. 定时发布 → 发送延迟 MQ 消息
178→        if (isTimed) {
179→            try {
180→                long delayMillis = Duration.between(LocalDateTime.now(), publishTime).toMillis();
181→                Message mqMessage = new Message(entity.getId().toString().getBytes());
182→                rabbitMqSender.sendDelayedMessage(QueueConfig.ANNOUNCEMENT_EXCHANGE, QueueConfig.ANNOUNCEMENT_KEY, mqMessage, delayMillis);
183→                log.info("[lbl][2210-公告][Announcement][CREATE] 定时发布任务已入队, announcementId={}, delayMs={}", entity.getId(), delayMillis);
184→            } catch (Exception e) {
185→                log.error("[lbl][2210-公告][Announcement][CREATE] 定时发布任务入队失败, announcementId={}, error={}", entity.getId(), e.getMessage(), e);
186→                operationMessage += "（定时任务创建失败，请重试）";
187→            }
188→        } else {
189→            // 立即发布 → 推送 WebSocket 通知
190→            pushAnnouncementNotification(entity);
191→        }
192→
193→        CreateAnnouncementVo result = new CreateAnnouncementVo();
194→        result.setId(entity.getId());
195→        result.setTitle(entity.getTitle());
196→        result.setContent(entity.getContent());
197→        result.setPublishTime(entity.getPublishTime());
198→        result.setMessage(operationMessage);
199→
200→        log.info("[lbl][2210-公告][Announcement][CREATE] 创建/更新完成, announcementId={}, userId={}, message={}", entity.getId(), userId, operationMessage);
201→        return result;
202→    }
