430→        List<AnnouncementEntity> updateList = interAnnouncementList.stream()
431→                .filter(o -> announcementIdList.contains(o.getId())).toList();
432→        List<AnnouncementEntity> addList = exactAnnouncementList.stream()
433→                .filter(o -> !existedAnnouncementIdList.contains(o.getId())).toList();
434→
435→        for (AnnouncementEntity addAnnouncement : addList) {
436→            announcementMapper.insert(addAnnouncement);
437→        }
438→        for (AnnouncementEntity updateAnnouncement : updateList) {
439→            announcementMapper.updateById(updateAnnouncement);
440→        }
