package com.yottastudios.ns.collabspace.announcement.consumer;

import com.rabbitmq.client.Channel;
import com.yottastudios.ns.collabspace.announcement.service.IAnnouncementService;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.amqp.core.Message;
import org.springframework.amqp.rabbit.annotation.RabbitListener;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
import org.springframework.stereotype.Component;

import java.io.IOException;

import static com.yottastudios.ns.collabspace.shared.config.QueueConfig.ANNOUNCEMENT_QUEUE;

@Slf4j
@Component
@ConditionalOnProperty(name = "mq.enabled", havingValue = "true", matchIfMissing = true)
public class AnnouncementConsumer {

    @Resource
    private IAnnouncementService announcementService;

    @RabbitListener(queues = ANNOUNCEMENT_QUEUE)
    public void handle(Message message, Channel channel) throws IOException {
        String body = new String(message.getBody());
        log.info("[Announcement][Consumer] 收到定时公告消息, announcementId={}", body);
        Long announcementId = Long.parseLong(body);
        try {
            announcementService.publishTimedAnnouncement(announcementId);
        } catch (Exception e) {
            log.error("[Announcement][Consumer] 定时公告发布失败, announcementId={}, error={}", announcementId, e.getMessage(), e);
        } finally {
            // 先不考虑重试
            long deliveryTag = message.getMessageProperties().getDeliveryTag();
            channel.basicAck(deliveryTag, false);
        }
    }
}

