package com.yottastudios.ns.collabspace.announcement.consumer;

import cn.hutool.json.JSONUtil;
import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import com.rabbitmq.client.Channel;
import com.yottastudios.ns.collabspace.announcement.entity.AnnouncementEntity;
import com.yottastudios.ns.collabspace.announcement.enums.AnnouncementCategory;
import com.yottastudios.ns.collabspace.announcement.enums.AnnouncementStatus;
import com.yottastudios.ns.collabspace.announcement.enums.AnnouncementType;
import com.yottastudios.ns.collabspace.announcement.mapper.AnnouncementMapper;
import com.yottastudios.ns.collabspace.starter.socketio.core.MessageTypeEnum;
import com.yottastudios.ns.collabspace.starter.socketio.core.WebSocketHandler;
import com.yottastudios.ns.collabspace.starter.socketio.core.WebSocketResponseModel;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.amqp.core.Message;
import org.springframework.amqp.rabbit.annotation.RabbitListener;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
import org.springframework.stereotype.Component;

import java.io.IOException;
import java.time.LocalDateTime;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

import static com.yottastudios.ns.collabspace.shared.config.QueueConfig.ANNOUNCEMENT_QUEUE;

@Slf4j
@Component
@ConditionalOnProperty(name = "mq.enabled", havingValue = "true", matchIfMissing = true)
public class AnnouncementConsumer {
    @Resource
    AnnouncementMapper announcementMapper;

    @Resource
    WebSocketHandler webSocketHandler;

    @RabbitListener(queues = ANNOUNCEMENT_QUEUE)
    public void handle(Message message, Channel channel) throws IOException {
        String body = new String(message.getBody());
        log.info("[lbl][2210-公告][Consumer][RECEIVE] 收到定时公告消息, announcementId={}", body);
        Long announcementId = Long.parseLong(body);
        try {
            AnnouncementEntity announcement = announcementMapper.selectById(announcementId);
            // 公告不存在、已取消或为立即发布类型，跳过处理
            if (announcement == null
                    || announcement.getStatus() == AnnouncementStatus.CANCELLED.getCode()
                    || announcement.getType() == AnnouncementType.IMMEDIATE.getCode()) {
                throw new RuntimeException("公告不需要发布");
            }

            LocalDateTime now = LocalDateTime.now();

            // 自动下线同分类下已发布的其他公告（同一时间只允许一条公告在线）
            LambdaQueryWrapper<AnnouncementEntity> activeWrapper = new LambdaQueryWrapper<AnnouncementEntity>()
                    .eq(AnnouncementEntity::getStatus, AnnouncementStatus.PUBLISHED.getCode())
                    .eq(AnnouncementEntity::getAnnouncementCategory, announcement.getAnnouncementCategory())
                    .ne(AnnouncementEntity::getId, announcement.getId());

            if (announcement.getAnnouncementCategory() != null
                    && announcement.getAnnouncementCategory() == AnnouncementCategory.SPACE.getCode()) {
                // 空间站公告：同 spaceId 下互斥
                activeWrapper.eq(AnnouncementEntity::getSpaceId, announcement.getSpaceId());
            } else {
                // 平台公告：spaceId 为 null 的互斥
                activeWrapper.isNull(AnnouncementEntity::getSpaceId);
            }

            List<AnnouncementEntity> activeList = announcementMapper.selectList(activeWrapper);
            for (AnnouncementEntity active : activeList) {
                active.setStatus(AnnouncementStatus.OFFLINE.getCode());
                active.setOfflineTime(now);
                announcementMapper.updateById(active);
                log.info("[lbl][2210-公告][Consumer][UPDATE] 自动下线旧公告, announcementId={}", active.getId());
            }

            // 更新当前公告状态为已发布
            announcement.setStatus(AnnouncementStatus.PUBLISHED.getCode());
            announcement.setPublishTime(now);
            announcementMapper.updateById(announcement);

            // 推送 WebSocket 通知，携带 spaceId/category/announcementId 供客户端精准刷新
            Map<String, Object> data = new HashMap<>();
            data.put("spaceId", announcement.getSpaceId());
            data.put("category", announcement.getAnnouncementCategory());
            data.put("announcementId", announcement.getId());

            WebSocketResponseModel wsModel = WebSocketResponseModel.builder()
                    .type(MessageTypeEnum.ADD_ANNOUNCEMENT.getType())
                    .message("更新公告").status(200).data(data).build();
            String msg = JSONUtil.toJsonStr(wsModel);
            webSocketHandler.sendAllUserToWebSocketClient(msg);

            log.info("[lbl][2210-公告][Consumer][UPDATE] 定时公告发布成功, announcementId={}, spaceId={}, category={}",
                    announcement.getId(), announcement.getSpaceId(), announcement.getAnnouncementCategory());
        } catch (Exception e) {
            log.error("[lbl][2210-公告][Consumer][UPDATE] 定时公告发布失败, announcementId={}, error={}", announcementId, e.getMessage(), e);
        } finally {
            // 先不考虑重试
            long deliveryTag = message.getMessageProperties().getDeliveryTag();
            channel.basicAck(deliveryTag, false);
        }
    }
}

