package com.yottastudios.ns.collabspace.announcement.service.impl;

import cn.hutool.json.JSONUtil;
import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import com.baomidou.mybatisplus.core.conditions.query.QueryWrapper;
import com.baomidou.mybatisplus.extension.service.impl.ServiceImpl;
import com.yottastudios.ns.collabspace.announcement.entity.AnnouncementEntity;
import com.yottastudios.ns.collabspace.announcement.entity.AnnouncementReadRecordEntity;
import com.yottastudios.ns.collabspace.announcement.enums.AnnouncementCategory;
import com.yottastudios.ns.collabspace.announcement.enums.AnnouncementStatus;
import com.yottastudios.ns.collabspace.announcement.enums.AnnouncementType;
import com.yottastudios.ns.collabspace.announcement.manager.AnnouncementReadRecordManager;
import com.yottastudios.ns.collabspace.announcement.mapper.AnnouncementMapper;
import com.yottastudios.ns.collabspace.announcement.mapper.AnnouncementReadRecordMapper;
import com.yottastudios.ns.collabspace.announcement.ro.CreateAnnouncementRo;
import com.yottastudios.ns.collabspace.announcement.ro.RepublishAnnouncementRo;
import com.yottastudios.ns.collabspace.announcement.ro.UpdateAnnouncementRo;
import com.yottastudios.ns.collabspace.announcement.service.IAnnouncementService;
import com.yottastudios.ns.collabspace.announcement.vo.ActiveAnnouncementVo;
import com.yottastudios.ns.collabspace.announcement.vo.CreateAnnouncementVo;
import com.yottastudios.ns.collabspace.announcement.vo.GetListAnnouncementVo;
import com.yottastudios.ns.collabspace.core.exception.BusinessException;
import com.yottastudios.ns.collabspace.grpc.ICollabspaceGrpcClientService;
import com.yottastudios.ns.collabspace.grpc.impl.ApitableGrpcClientServiceImpl;
import com.yottastudios.ns.collabspace.shared.config.QueueConfig;
import com.yottastudios.ns.collabspace.space.manager.query.SpaceQueryManager;
import com.yottastudios.ns.collabspace.shared.context.SessionContext;
import com.yottastudios.ns.collabspace.shared.mq.RabbitMqSender;
import com.yottastudios.ns.collabspace.shared.util.CollectionUtil;
import com.yottastudios.ns.collabspace.starter.socketio.core.MessageTypeEnum;
import com.yottastudios.ns.collabspace.starter.socketio.core.WebSocketHandler;
import com.yottastudios.ns.collabspace.starter.socketio.core.WebSocketResponseModel;
import com.yottastudios.ns.collabspace.user.vo.UserSimpleInfoVo;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.amqp.core.Message;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import org.springframework.util.StringUtils;

import java.time.Duration;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

@Slf4j
@Service
public class AnnouncementImpl extends ServiceImpl<AnnouncementMapper, AnnouncementEntity> implements IAnnouncementService {

    private static final DateTimeFormatter DATE_TIME_FORMATTER = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");

    @Resource
    private AnnouncementMapper announcementMapper;

    @Resource
    private AnnouncementReadRecordMapper announcementReadRecordMapper;

    @Resource
    private ApitableGrpcClientServiceImpl apitableGrpcClientService;

    @Resource
    private AnnouncementReadRecordManager announcementReadRecordManager;

    @Resource
    private ICollabspaceGrpcClientService collabspaceGrpcClientService;

    @Resource
    RabbitMqSender rabbitMqSender;

    @Resource
    WebSocketHandler webSocketHandler;

    @Resource
    private SpaceQueryManager spaceQueryManager;

    @Override
    @Transactional(rollbackFor = Exception.class)
    public CreateAnnouncementVo createAnnouncement(CreateAnnouncementRo ro) {
        log.info("[lbl][2210-公告][Announcement][CREATE] 开始创建/更新公告, category={}, spaceId={}, title={}", ro.getAnnouncementCategory(), ro.getSpaceId(), ro.getTitle());

        // 0. 兼容旧前端：不传 announcementCategory 时，根据 spaceId 推断类别
        if (ro.getAnnouncementCategory() == null) {
            ro.setAnnouncementCategory(StringUtils.hasText(ro.getSpaceId())
                    ? AnnouncementCategory.SPACE.getCode()
                    : AnnouncementCategory.PLATFORM.getCode());
        }

        // 1. 空间站公告需校验管理员权限（主管理员 或 文档管理员）
        checkSpaceAnnouncementPermission(ro.getAnnouncementCategory(), ro.getSpaceId());

        // 2. 校验基本入参
        if (!StringUtils.hasText(ro.getTitle())) {
            throw new BusinessException("公告标题不能为空");
        }
        if (!StringUtils.hasText(ro.getContent())) {
            throw new BusinessException("公告内容不能为空");
        }

        LocalDateTime now = LocalDateTime.now();
        LocalDateTime publishTime;
        if (StringUtils.hasText(ro.getPublishTime())) {
            publishTime = LocalDateTime.parse(ro.getPublishTime(), DATE_TIME_FORMATTER);
        } else {
            // 无发布时间 = 立即发布
            publishTime = now;
        }

        // 判断是否定时：发布时间比当前晚 10 分钟以上才算定时
        boolean isTimed = publishTime.isAfter(now.plusMinutes(10));
        // 明确传了未来时间（超过1分钟容差）但不足10分钟，拒绝；1分钟内视为"立即发布"兼容时钟偏差
        if (!isTimed && StringUtils.hasText(ro.getPublishTime()) && publishTime.isAfter(now.plusMinutes(1))) {
            throw new BusinessException("定时发布时间必须晚于当前时间至少 10 分钟");
        }

        // 校验过期时间
        if (StringUtils.hasText(ro.getExpireTime())) {
            LocalDateTime expireTime = LocalDateTime.parse(ro.getExpireTime(), DATE_TIME_FORMATTER);
            if (!expireTime.isAfter(publishTime)) {
                throw new BusinessException("过期时间必须晚于发布时间");
            }
        }

        // 2. 获取当前用户信息
        Long userId = SessionContext.getUserId();
        UserSimpleInfoVo userInfo = apitableGrpcClientService.getUserById(userId);
        String userName = userInfo != null ? userInfo.getNickName() : "";

        // 3. 如果是编辑（announcementId != null），将旧公告下线
        if (ro.getAnnouncementId() != null) {
            AnnouncementEntity old = announcementMapper.selectById(ro.getAnnouncementId());
            if (old != null) {
                old.setStatus(AnnouncementStatus.OFFLINE.getCode());
                old.setOfflineTime(now);
                announcementMapper.updateById(old);
                log.info("[lbl][2210-公告][Announcement][UPDATE] 编辑操作将旧公告下线, announcementId={}", old.getId());
            }
        }

        // 4. 检查同类型（spaceId + category）是否有当前生效公告，自动下线
        offlineActiveAnnouncementByCategory(ro.getSpaceId(), ro.getAnnouncementCategory(), now);

        // 5. 构建新公告实体（始终 INSERT）
        AnnouncementEntity entity = new AnnouncementEntity();
        entity.setTitle(ro.getTitle());
        entity.setContent(ro.getContent());
        entity.setIsPopup(ro.getIsPopup() != null ? ro.getIsPopup() : false);
        entity.setSpaceId(ro.getSpaceId());
        entity.setAnnouncementCategory(ro.getAnnouncementCategory());
        entity.setCreatorId(userId);
        entity.setCreatorName(userName);
        entity.setPublisherId(userId);
        entity.setPublisherName(userName);
        entity.setPublishTime(publishTime);
        if (StringUtils.hasText(ro.getExpireTime())) {
            entity.setExpireTime(LocalDateTime.parse(ro.getExpireTime(), DATE_TIME_FORMATTER));
        }

        String operationMessage;
        if (isTimed) {
            // 6. 定时发布
            entity.setType(AnnouncementType.TIMED.getCode());
            entity.setStatus(AnnouncementStatus.TIMED.getCode());
            operationMessage = "公告已设置定时发布";
        } else {
            // 7. 立即发布
            entity.setType(AnnouncementType.IMMEDIATE.getCode());
            entity.setStatus(AnnouncementStatus.PUBLISHED.getCode());
            entity.setPublishTime(now);
            operationMessage = "公告已立即发布";
        }

        // 8. INSERT 新实体
        announcementMapper.insert(entity);
        log.info("[lbl][2210-公告][Announcement][CREATE] 新公告已创建, announcementId={}, status={}, category={}, spaceId={}", entity.getId(), entity.getStatus(), entity.getAnnouncementCategory(), entity.getSpaceId());

        // 9. 定时发布 → 发送延迟 MQ 消息
        if (isTimed) {
            try {
                long delayMillis = Duration.between(LocalDateTime.now(), publishTime).toMillis();
                Message mqMessage = new Message(entity.getId().toString().getBytes());
                rabbitMqSender.sendDelayedMessage(QueueConfig.ANNOUNCEMENT_EXCHANGE, QueueConfig.ANNOUNCEMENT_KEY, mqMessage, delayMillis);
                log.info("[lbl][2210-公告][Announcement][CREATE] 定时发布任务已入队, announcementId={}, delayMs={}", entity.getId(), delayMillis);
            } catch (Exception e) {
                log.error("[lbl][2210-公告][Announcement][CREATE] 定时发布任务入队失败, announcementId={}, error={}", entity.getId(), e.getMessage(), e);
                operationMessage += "（定时任务创建失败，请重试）";
            }
        } else {
            // 立即发布 → 推送 WebSocket 通知
            pushAnnouncementNotification(entity);
        }

        CreateAnnouncementVo result = new CreateAnnouncementVo();
        result.setId(entity.getId());
        result.setTitle(entity.getTitle());
        result.setContent(entity.getContent());
        result.setPublishTime(entity.getPublishTime());
        result.setMessage(operationMessage);

        log.info("[lbl][2210-公告][Announcement][CREATE] 创建/更新完成, announcementId={}, userId={}, message={}", entity.getId(), userId, operationMessage);
        return result;
    }

    @Override
    public List<GetListAnnouncementVo> getAnnounceList(int status, String spaceId, Integer announcementCategory) {
        LambdaQueryWrapper<AnnouncementEntity> wrapper = new LambdaQueryWrapper<AnnouncementEntity>()
                .eq(AnnouncementEntity::getStatus, status)
                .eq(AnnouncementEntity::getIsDeleted, false)
                .eq(StringUtils.hasText(spaceId), AnnouncementEntity::getSpaceId, spaceId)
                .eq(announcementCategory != null, AnnouncementEntity::getAnnouncementCategory, announcementCategory)
                .orderByDesc(AnnouncementEntity::getPublishTime);

        List<AnnouncementEntity> entityList = announcementMapper.selectList(wrapper);
        return entityList.stream().map(this::convertToListVo).toList();
    }

    @Override
    public Boolean changeAnnouncementStatus(UpdateAnnouncementRo ro) {
        return doChangeAnnouncementStatus(ro, false);
    }

    @Override
    public Boolean changeAnnouncementStatusByAdmin(UpdateAnnouncementRo ro) {
        return doChangeAnnouncementStatus(ro, true);
    }

    private Boolean doChangeAnnouncementStatus(UpdateAnnouncementRo ro, boolean skipPermissionCheck) {
        AnnouncementEntity announcement = announcementMapper.selectById(ro.getAnnouncementId());
        if (announcement == null) {
            return false;
        }
        if (!skipPermissionCheck) {
            checkPlatformAnnouncementWritePermission(announcement.getAnnouncementCategory());
            checkSpaceAnnouncementPermission(announcement.getAnnouncementCategory(), announcement.getSpaceId());
        }
        if (ro.getStatus() != null) {
            announcement.setStatus(ro.getStatus());
            // 下线时同步记录下线时间
            if (ro.getStatus() == AnnouncementStatus.OFFLINE.getCode()) {
                announcement.setOfflineTime(LocalDateTime.now());
            }
        }
        if (ro.getType() != null) {
            announcement.setType(ro.getType());
        }
        boolean result = announcementMapper.updateById(announcement) > 0;
        log.info("[lbl][2210-公告][Announcement][UPDATE] 修改公告状态, announcementId={}, status={}, type={}, result={}", ro.getAnnouncementId(), ro.getStatus(), ro.getType(), result);
        return result;
    }

    @Override
    public GetListAnnouncementVo getLastAnnouncement() {
        GetListAnnouncementVo vo = new GetListAnnouncementVo();
        // 向后兼容：只查 PLATFORM 类型公告
        AnnouncementEntity announcement = announcementMapper.selectOne(new LambdaQueryWrapper<AnnouncementEntity>()
                .eq(AnnouncementEntity::getStatus, AnnouncementStatus.PUBLISHED.getCode())
                .eq(AnnouncementEntity::getIsDeleted, false)
                .eq(AnnouncementEntity::getAnnouncementCategory, AnnouncementCategory.PLATFORM.getCode())
                .orderByDesc(AnnouncementEntity::getCreatedAt)
                .last("LIMIT 1"));

        if (announcement == null) {
            return vo;
        }

        // 修复原有 bug：正确判断是否已读
        AnnouncementReadRecordEntity readRecord = announcementReadRecordManager
                .selectByAnnouncementIdAndUserId(announcement.getId(), SessionContext.getUserId());
        boolean hasRead = readRecord != null;
        if (hasRead) {
            return vo;
        }

        vo.setTitle(announcement.getTitle());
        vo.setContent(announcement.getContent());
        vo.setPublishTime(announcement.getPublishTime());
        vo.setIsPopup(announcement.getIsPopup());
        vo.setId(announcement.getId());
        // 记录已读
        addAnnouncementReadRecord(vo.getId(), announcement.getSpaceId());
        return vo;
    }

    @Override
    public void addAnnouncementReadRecord(Long announcementId, String spaceId) {
        Long currentUserId = SessionContext.getUserId();
        // 幂等：已存在则跳过
        AnnouncementReadRecordEntity existed =
                announcementReadRecordManager.selectByAnnouncementIdAndUserId(announcementId, currentUserId);
        if (existed != null) {
            return;
        }
        AnnouncementReadRecordEntity readRecord = new AnnouncementReadRecordEntity();
        readRecord.setUserId(currentUserId);
        readRecord.setAnnouncementId(announcementId);
        readRecord.setSpaceId(spaceId != null ? spaceId : "");
        readRecord.setReadTime(LocalDateTime.now());
        announcementReadRecordMapper.insert(readRecord);
        log.info("[lbl][2210-公告][ReadRecord][CREATE] 记录已读, announcementId={}, userId={}, spaceId={}", announcementId, currentUserId, spaceId);
    }

    @Override
    public Boolean judgeRedPots(String spaceId) {
        Long currentUserId = SessionContext.getUserId();

        // 检查平台公告未读
        boolean platformUnread = hasUnreadAnnouncement(currentUserId,
                null, AnnouncementCategory.PLATFORM.getCode());
        if (platformUnread) {
            return true;
        }

        // 检查空间站公告未读
        boolean spaceUnread = hasUnreadAnnouncement(currentUserId,
                spaceId, AnnouncementCategory.SPACE.getCode());
        return spaceUnread;
    }

    @Override
    public List<ActiveAnnouncementVo> getActiveAnnouncements(String spaceId) {
        Long currentUserId = SessionContext.getUserId();
        List<ActiveAnnouncementVo> result = new ArrayList<>();

        // 1. 查平台公告（最新 1 条）
        AnnouncementEntity platform = announcementMapper.selectOne(new LambdaQueryWrapper<AnnouncementEntity>()
                .eq(AnnouncementEntity::getStatus, AnnouncementStatus.PUBLISHED.getCode())
                .eq(AnnouncementEntity::getAnnouncementCategory, AnnouncementCategory.PLATFORM.getCode())
                .orderByDesc(AnnouncementEntity::getPublishTime)
                .last("LIMIT 1"));
        if (platform != null) {
            result.add(buildActiveVo(platform, currentUserId));
        }

        // 2. 查空间站公告（最新 1 条）
        AnnouncementEntity space = announcementMapper.selectOne(new LambdaQueryWrapper<AnnouncementEntity>()
                .eq(AnnouncementEntity::getStatus, AnnouncementStatus.PUBLISHED.getCode())
                .eq(AnnouncementEntity::getAnnouncementCategory, AnnouncementCategory.SPACE.getCode())
                .eq(AnnouncementEntity::getSpaceId, spaceId)
                .orderByDesc(AnnouncementEntity::getPublishTime)
                .last("LIMIT 1"));
        if (space != null) {
            result.add(buildActiveVo(space, currentUserId));
        }

        return result;
    }

    @Override
    public List<GetListAnnouncementVo> getHistoryList(String spaceId, Integer announcementCategory) {
        LambdaQueryWrapper<AnnouncementEntity> wrapper = new LambdaQueryWrapper<AnnouncementEntity>()
                .in(AnnouncementEntity::getStatus,
                        AnnouncementStatus.OFFLINE.getCode(),
                        AnnouncementStatus.CANCELLED.getCode())
                .eq(AnnouncementEntity::getIsDeleted, false)
                .eq(announcementCategory != null, AnnouncementEntity::getAnnouncementCategory, announcementCategory)
                .orderByDesc(AnnouncementEntity::getPublishTime);

        if (announcementCategory != null && announcementCategory == AnnouncementCategory.SPACE.getCode()) {
            wrapper.eq(AnnouncementEntity::getSpaceId, spaceId);
        }

        return announcementMapper.selectList(wrapper).stream().map(this::convertToListVo).toList();
    }

    @Override
    public Boolean deleteAnnouncement(Long announcementId) {
        return doDeleteAnnouncement(announcementId, false);
    }

    @Override
    public Boolean deleteAnnouncementByAdmin(Long announcementId) {
        return doDeleteAnnouncement(announcementId, true);
    }

    private Boolean doDeleteAnnouncement(Long announcementId, boolean skipPermissionCheck) {
        AnnouncementEntity announcement = announcementMapper.selectById(announcementId);
        if (announcement == null) {
            return false;
        }
        if (!skipPermissionCheck) {
            checkPlatformAnnouncementWritePermission(announcement.getAnnouncementCategory());
            checkSpaceAnnouncementPermission(announcement.getAnnouncementCategory(), announcement.getSpaceId());
        }
        // MyBatis-Plus deleteById 走逻辑删除（@TableLogic）
        boolean result = announcementMapper.deleteById(announcementId) > 0;
        log.info("[Announcement][DELETE] 软删除公告, announcementId={}, userId={}, result={}", announcementId, SessionContext.getUserId(), result);
        return result;
    }

    @Override
    public CreateAnnouncementVo republishAnnouncement(RepublishAnnouncementRo ro) {
        AnnouncementEntity old = announcementMapper.selectById(ro.getAnnouncementId());
        if (old == null) {
            throw new BusinessException("公告不存在，无法重新发布");
        }
        // 用旧公告内容构建新的 CreateAnnouncementRo，允许覆盖部分字段
        CreateAnnouncementRo createRo = CreateAnnouncementRo.builder()
                .title(old.getTitle())
                .content(old.getContent())
                .isPopup(ro.getIsPopup() != null ? ro.getIsPopup() : old.getIsPopup())
                .spaceId(ro.getSpaceId() != null ? ro.getSpaceId() : old.getSpaceId())
                .announcementCategory(ro.getAnnouncementCategory())
                .publishTime(ro.getPublishTime())
                .expireTime(ro.getExpireTime())
                .build();
        log.info("[lbl][2210-公告][Announcement][CREATE] 重新发布, 原announcementId={}, category={}, userId={}", ro.getAnnouncementId(), ro.getAnnouncementCategory(), SessionContext.getUserId());
        return createAnnouncement(createRo);
    }

    @Override
    public void offlineExpiredAnnouncements() {
        LocalDateTime now = LocalDateTime.now();
        List<AnnouncementEntity> expiredList = announcementMapper.selectList(new LambdaQueryWrapper<AnnouncementEntity>()
                .eq(AnnouncementEntity::getStatus, AnnouncementStatus.PUBLISHED.getCode())
                .isNotNull(AnnouncementEntity::getExpireTime)
                .lt(AnnouncementEntity::getExpireTime, now));
        if (expiredList.isEmpty()) {
            return;
        }
        log.info("[Announcement][ExpireTask] 扫描到 {} 条已到期公告，开始自动下线", expiredList.size());
        for (AnnouncementEntity entity : expiredList) {
            entity.setStatus(AnnouncementStatus.OFFLINE.getCode());
            entity.setOfflineTime(now);
            announcementMapper.updateById(entity);
            // 通知客户端公告已下线
            pushOfflineNotification(entity);
            log.info("[Announcement][ExpireTask] 到期自动下线, announcementId={}, expireTime={}", entity.getId(), entity.getExpireTime());
        }
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public void publishTimedAnnouncement(Long announcementId) {
        AnnouncementEntity announcement = announcementMapper.selectById(announcementId);
        // 公告不存在、已取消或为立即发布类型，跳过处理
        if (announcement == null
                || announcement.getStatus() == AnnouncementStatus.CANCELLED.getCode()
                || announcement.getType() == AnnouncementType.IMMEDIATE.getCode()) {
            log.info("[Announcement][Consumer] 公告无需发布, announcementId={}, status={}, type={}",
                    announcementId,
                    announcement != null ? announcement.getStatus() : "null",
                    announcement != null ? announcement.getType() : "null");
            return;
        }

        LocalDateTime now = LocalDateTime.now();

        // 自动下线同分类下已发布的其他公告
        offlineActiveAnnouncementByCategory(announcement.getSpaceId(), announcement.getAnnouncementCategory(), now);

        // 更新当前公告状态为已发布
        announcement.setStatus(AnnouncementStatus.PUBLISHED.getCode());
        announcement.setPublishTime(now);
        announcementMapper.updateById(announcement);

        // 推送 WebSocket 通知
        pushAnnouncementNotification(announcement);

        log.info("[Announcement][Consumer] 定时公告发布成功, announcementId={}, spaceId={}, category={}",
                announcement.getId(), announcement.getSpaceId(), announcement.getAnnouncementCategory());
    }

    @Override
    public void syncAnnouncement() {
        // 轮询接口：从外网同步公告
        List<AnnouncementEntity> exactAnnouncementList = collabspaceGrpcClientService.getExactAnnouncement();
        List<Long> announcementIdList = exactAnnouncementList.stream().map(AnnouncementEntity::getId).toList();
        List<AnnouncementEntity> interAnnouncementList = CollectionUtil.isEmpty(announcementIdList) ? new ArrayList<>()
                : announcementMapper.selectBatchIds(announcementIdList);
        List<Long> existedAnnouncementIdList = interAnnouncementList.stream().map(AnnouncementEntity::getId).toList();
        List<AnnouncementEntity> updateList = interAnnouncementList.stream()
                .filter(o -> announcementIdList.contains(o.getId())).toList();
        List<AnnouncementEntity> addList = exactAnnouncementList.stream()
                .filter(o -> !existedAnnouncementIdList.contains(o.getId())).toList();

        for (AnnouncementEntity addAnnouncement : addList) {
            announcementMapper.insert(addAnnouncement);
        }
        for (AnnouncementEntity updateAnnouncement : updateList) {
            announcementMapper.updateById(updateAnnouncement);
        }
    }

    @Override
    public List<GetListAnnouncementVo> getAnnouncementById(List<Long> announcementIdListList) {
        List<AnnouncementEntity> list = announcementMapper.selectBatchIds(announcementIdListList);
        return list.stream().map(this::convertToListVo).toList();
    }

    // ===== 私有辅助方法 =====

    /**
     * 空间站公告权限校验：仅主管理员或文档管理员可操作
     * 平台公告不在此校验（由 manageback 网关/拦截器控制）
     */
    private void checkSpaceAnnouncementPermission(Integer category, String spaceId) {
        if (category == null || category != AnnouncementCategory.SPACE.getCode()) {
            return;
        }
        if (!StringUtils.hasText(spaceId)) {
            throw new BusinessException("空间站公告必须指定 spaceId");
        }
        Long userId = SessionContext.getUserId();
        boolean isAdmin = spaceQueryManager.isUserSpaceAdmin(userId, spaceId);
        if (!isAdmin) {
            log.warn("[lbl][2210-公告][Announcement][AUTH] 无权操作空间站公告, userId={}, spaceId={}", userId, spaceId);
            throw new BusinessException("无权操作：仅空间站管理员或文档管理员可发布/修改空间站公告");
        }
    }

    /**
     * 检查平台公告写操作权限：前台接口不允许修改/删除平台公告
     */
    private void checkPlatformAnnouncementWritePermission(Integer category) {
        if (category != null && category == AnnouncementCategory.PLATFORM.getCode()) {
            log.warn("[lbl][2210-公告][Announcement][AUTH] 前台接口尝试操作平台公告, userId={}", SessionContext.getUserId());
            throw new BusinessException("平台公告请通过管理后台操作");
        }
    }

    /**
     * 将同类型（spaceId + category）的已发布公告批量下线
     */
    private void offlineActiveAnnouncementByCategory(String spaceId, Integer category, LocalDateTime now) {
        LambdaQueryWrapper<AnnouncementEntity> wrapper = new LambdaQueryWrapper<AnnouncementEntity>()
                .eq(AnnouncementEntity::getStatus, AnnouncementStatus.PUBLISHED.getCode())
                .eq(AnnouncementEntity::getAnnouncementCategory, category);
        if (category == AnnouncementCategory.SPACE.getCode()) {
            wrapper.eq(AnnouncementEntity::getSpaceId, spaceId);
        } else {
            wrapper.isNull(AnnouncementEntity::getSpaceId);
        }
        List<AnnouncementEntity> activeList = announcementMapper.selectList(wrapper);
        for (AnnouncementEntity active : activeList) {
            active.setStatus(AnnouncementStatus.OFFLINE.getCode());
            active.setOfflineTime(now);
            announcementMapper.updateById(active);
            log.info("[lbl][2210-公告][Announcement][UPDATE] 自动下线旧公告, announcementId={}, category={}", active.getId(), category);
        }
    }

    /**
     * 向所有 WebSocket 连接广播新公告通知，前端按 spaceId 过滤
     */
    private void pushAnnouncementNotification(AnnouncementEntity entity) {
        Map<String, Object> data = new HashMap<>();
        data.put("spaceId", entity.getSpaceId());
        data.put("category", entity.getAnnouncementCategory());
        data.put("announcementId", entity.getId());

        WebSocketResponseModel wsModel = WebSocketResponseModel.builder()
                .type(MessageTypeEnum.ADD_ANNOUNCEMENT.getType())
                .message("更新公告").status(200).data(data).build();
        String msg = JSONUtil.toJsonStr(wsModel);
        // 广播给全部用户，由前端根据 spaceId 决定是否展示
        webSocketHandler.sendAllUserToWebSocketClient(msg);
        log.info("[lbl][2210-公告][WS][PUSH] WebSocket 通知已推送, announcementId={}, category={}, spaceId={}", entity.getId(), entity.getAnnouncementCategory(), entity.getSpaceId());
    }

    /**
     * 向所有 WebSocket 连接广播公告下线通知
     */
    private void pushOfflineNotification(AnnouncementEntity entity) {
        Map<String, Object> data = new HashMap<>();
        data.put("spaceId", entity.getSpaceId());
        data.put("category", entity.getAnnouncementCategory());
        data.put("announcementId", entity.getId());
        data.put("action", "OFFLINE");

        WebSocketResponseModel wsModel = WebSocketResponseModel.builder()
                .type(MessageTypeEnum.ADD_ANNOUNCEMENT.getType())
                .message("公告下线").status(200).data(data).build();
        String msg = JSONUtil.toJsonStr(wsModel);
        webSocketHandler.sendAllUserToWebSocketClient(msg);
    }

    /**
     * 判断指定用户对某类型最新公告是否未读
     */
    private boolean hasUnreadAnnouncement(Long userId, String spaceId, int category) {
        LambdaQueryWrapper<AnnouncementEntity> wrapper = new LambdaQueryWrapper<AnnouncementEntity>()
                .eq(AnnouncementEntity::getStatus, AnnouncementStatus.PUBLISHED.getCode())
                .eq(AnnouncementEntity::getAnnouncementCategory, category)
                .orderByDesc(AnnouncementEntity::getPublishTime)
                .last("LIMIT 1");
        if (category == AnnouncementCategory.SPACE.getCode()) {
            if (!StringUtils.hasText(spaceId)) {
                return false;
            }
            wrapper.eq(AnnouncementEntity::getSpaceId, spaceId);
        }
        AnnouncementEntity latest = announcementMapper.selectOne(wrapper);
        if (latest == null) {
            return false;
        }
        AnnouncementReadRecordEntity record =
                announcementReadRecordManager.selectByAnnouncementIdAndUserId(latest.getId(), userId);
        return record == null;
    }

    /**
     * 构建 ActiveAnnouncementVo，包含已读状态
     */
    private ActiveAnnouncementVo buildActiveVo(AnnouncementEntity entity, Long userId) {
        AnnouncementReadRecordEntity record =
                announcementReadRecordManager.selectByAnnouncementIdAndUserId(entity.getId(), userId);
        return ActiveAnnouncementVo.builder()
                .id(entity.getId())
                .title(entity.getTitle())
                .content(entity.getContent())
                .isPopup(entity.getIsPopup())
                .publishTime(entity.getPublishTime())
                .expireTime(entity.getExpireTime())
                .announcementCategory(entity.getAnnouncementCategory())
                .spaceId(entity.getSpaceId())
                .publisherName(entity.getPublisherName())
                .hasRead(record != null)
                .build();
    }

    /**
     * 通用：将 AnnouncementEntity 转换为 GetListAnnouncementVo
     */
    private GetListAnnouncementVo convertToListVo(AnnouncementEntity entity) {
        GetListAnnouncementVo vo = new GetListAnnouncementVo();
        vo.setId(entity.getId());
        vo.setTitle(entity.getTitle());
        vo.setContent(entity.getContent());
        vo.setPublishTime(entity.getPublishTime());
        vo.setIsPopup(entity.getIsPopup());
        vo.setStatus(entity.getStatus());
        vo.setCreatorId(entity.getCreatorId());
        vo.setExpireTime(entity.getExpireTime());
        vo.setOfflineTime(entity.getOfflineTime());
        vo.setPublisherName(entity.getPublisherName());
        vo.setAnnouncementCategory(entity.getAnnouncementCategory());
        vo.setSpaceId(entity.getSpaceId());
        vo.setType(entity.getType());
        return vo;
    }
}

