@Override
public boolean checkSpaceName(String name){
    NameValidateUtil.validate(name);
    List<SpaceEntity> spaceEntities = spaceService.matchByName(name);
    return CollectionUtils.isNotEmpty(spaceEntities);
}

@Override
public List<SpaceMemberVo> getAllMembers(String spaceId) {
    List<SpaceMemberVo> allMembers = new ArrayList<>();
    int pageNum = 1;
    int pageSize = 500;

    while (true) {
        IPage<SpaceMemberVo> memberPage = apitableGrpcClientService.getSpaceMembers(spaceId, pageNum, pageSize);
        if (memberPage == null || memberPage.getRecords() == null || memberPage.getRecords().isEmpty()) {
            break;
        }

        allMembers.addAll(memberPage.getRecords());

        if (memberPage.getRecords().size() < pageSize) {
            break;
        }
        pageNum++;
    }

    return allMembers;
}

